namespace sv_e879deaebc64451b9de169120c2ff2c6.Services;

public class CartItem
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public decimal Price { get; set; }
    public int Quantity { get; set; }
}

public class CartState
{
    private readonly List<CartItem> _items = [];

    public IReadOnlyList<CartItem> Items => _items.AsReadOnly();

    public int TotalCount => _items.Sum(i => i.Quantity);

    public decimal TotalPrice => _items.Sum(i => i.Price * i.Quantity);

    public event Action? OnChange;

    public void Add(int id, string name, decimal price)
    {
        var existing = _items.FirstOrDefault(i => i.Id == id);
        if (existing is not null)
        {
            existing.Quantity++;
        }
        else
        {
            _items.Add(new CartItem { Id = id, Name = name, Price = price, Quantity = 1 });
        }
        OnChange?.Invoke();
    }

    public void Remove(int id)
    {
        var item = _items.FirstOrDefault(i => i.Id == id);
        if (item is not null)
        {
            _items.Remove(item);
            OnChange?.Invoke();
        }
    }

    public void Clear()
    {
        _items.Clear();
        OnChange?.Invoke();
    }
}

@using sv_e879deaebc64451b9de169120c2ff2c6.Services
@inject CartState Cart
@implements IDisposable

<NavLink class="nav-link" href="cart">
    <span class="bi bi-cart-fill-nav-menu" aria-hidden="true"></span>
    Cart
    @if (Cart.TotalCount > 0)
    {
        <span class="badge bg-danger rounded-pill ms-1">@Cart.TotalCount</span>
    }
</NavLink>

@code {
    protected override void OnInitialized()
    {
        Cart.OnChange += StateHasChanged;
    }

    public void Dispose()
    {
        Cart.OnChange -= StateHasChanged;
    }
}

@page "/products"
@rendermode InteractiveServer
@using sv_e879deaebc64451b9de169120c2ff2c6.Services
@inject CartState Cart

<PageTitle>Products</PageTitle>

<h1>Products</h1>

<div class="row row-cols-1 row-cols-md-3 g-4 mt-2">
    @foreach (var product in products)
    {
        <div class="col">
            <div class="card h-100">
                <div class="card-body">
                    <h5 class="card-title">@product.Name</h5>
                    <p class="card-text text-muted">@product.Description</p>
                    <p class="card-text fw-bold">@product.Price.ToString("C")</p>
                </div>
                <div class="card-footer">
                    <button class="btn btn-primary" @onclick="() => AddToCart(product)">
                        Add to Cart
                    </button>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private record Product(int Id, string Name, string Description, decimal Price);

    private readonly Product[] products =
    [
        new(1, "Wireless Mouse", "Ergonomic wireless mouse with USB receiver", 29.99m),
        new(2, "Mechanical Keyboard", "RGB backlit mechanical keyboard", 79.99m),
        new(3, "USB-C Hub", "7-in-1 USB-C hub with HDMI and Ethernet", 49.99m),
        new(4, "Monitor Stand", "Adjustable aluminum monitor stand", 39.99m),
        new(5, "Webcam HD", "1080p HD webcam with built-in microphone", 59.99m),
        new(6, "Desk Lamp", "LED desk lamp with adjustable brightness", 24.99m),
    ];

    private void AddToCart(Product product)
    {
        Cart.Add(product.Id, product.Name, product.Price);
    }
}

@page "/cart"
@rendermode InteractiveServer
@using sv_e879deaebc64451b9de169120c2ff2c6.Services
@inject CartState Cart
@implements IDisposable

<PageTitle>Cart</PageTitle>

<h1>Shopping Cart</h1>

@if (!Cart.Items.Any())
{
    <p class="text-muted mt-3">Your cart is empty.</p>
    <a href="products" class="btn btn-primary">Browse Products</a>
}
else
{
    <table class="table mt-3">
        <thead>
            <tr>
                <th>Product</th>
                <th>Price</th>
                <th>Quantity</th>
                <th>Subtotal</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var item in Cart.Items)
            {
                <tr>
                    <td>@item.Name</td>
                    <td>@item.Price.ToString("C")</td>
                    <td>@item.Quantity</td>
                    <td>@((item.Price * item.Quantity).ToString("C"))</td>
                    <td>
                        <button class="btn btn-sm btn-danger" @onclick="() => Cart.Remove(item.Id)">
                            Remove
                        </button>
                    </td>
                </tr>
            }
        </tbody>
    </table>

    <div class="d-flex justify-content-between align-items-center mt-3">
        <h4>Total: @Cart.TotalPrice.ToString("C")</h4>
        <button class="btn btn-outline-danger" @onclick="Cart.Clear">Clear Cart</button>
    </div>
}

@code {
    protected override void OnInitialized()
    {
        Cart.OnChange += StateHasChanged;
    }

    public void Dispose()
    {
        Cart.OnChange -= StateHasChanged;
    }
}

